const body = $input.first().json;

// Read.ai sends different payload shapes depending on version
// Normalize to a consistent shape
const meeting = body.meeting || body;

const title = meeting.title || meeting.name || 'Untitled Meeting';
const date = meeting.created_at || meeting.date || meeting.start_time || new Date().toISOString();
const recordingUrl = meeting.recording_url || meeting.video_url || '';
const summary = meeting.summary || meeting.overview || '';
const transcript = meeting.transcript || meeting.full_transcript || '';

// Flatten attendees to a string
const attendeesRaw = meeting.attendees || meeting.participants || [];
const attendeesStr = attendeesRaw
  .map(a => `${a.name || a.display_name || ''} <${a.email || ''}>`)
  .filter(s => s.trim() !== '<>')
  .join(', ');

// Page content: summary + transcript
const pageContent = [
  summary ? `## Summary\n\n${summary}` : '',
  transcript ? `## Transcript\n\n${transcript}` : '',
].filter(Boolean).join('\n\n');

return [{
  json: {
    title,
    date: date.split('T')[0], // YYYY-MM-DD
    recordingUrl,
    externalAttendees: attendeesStr,
    summary,
    pageContent,
  }
}];
